if GetLocale() ~= "deDE" then return end

IMAGO.LoreSnippets["FUN_FACT"] = {
    { text = "Geistheiler sind in Wahrheit abtrünnige Val'kyr." },
    { text = [[Nat Pagle sagte einst: „Man kann sie nicht alle an den Haken bekommen, wenn man nicht auswirft."]] },
    { text = "IMAGO – Die Chronik der Unvergessenen wird nie vollendet – nur erweitert." },
    { text = "Murlocs sprechen Nerglish." },
    { text = "Die Defiasbruderschaft hatte recht." },
    { text = "Bolvar Fordragon war länger der Lichkönig als Arthas Menethil." },
    { text = "Das Flüstern im Thronsaal von Lordaeron ist das letzte Gespräch zwischen Arthas und seinem Vater aus Warcraft III. Dreh deine Umgebungslaustärke auf, um es selbst zu hören!" },
    { text = "Kleintiere wie Robben und Eber sind bekanntermaßen explodiert, wenn man sie wiederholt angestupst hat. Dieses Phänomen hat seit dem Ende des Dritten Krieges auf mysteriöse Weise aufgehört." },
    { text = "Illidan Sturmgrimm führt die Kriegsgleven von Azzinoth. In ihrer ursprünglichen Darstellung hatten sie Pandagesichter in den Griff graviert." },
    { text = "Viele prominente Charaktere sind dafür bekannt, Tabak zu rauchen, darunter König Terenas, Khadgar, Uther Lichtbringer und Tirion Fordring." },
    { text = "Stratholme hat ein Schild, das den Weg ins Schlingendorntal weist, obwohl diese Region auf der anderen Seite des Kontinents liegt." },
    { text = "Schreckensrosse werden vom Stallmeister-Dämonenlord Hel'nurath auf dem Planeten Xoroth gezüchtet. Zu seinem Entsetzen stehlen Hexenmeister sie immer wieder für ihre Beschwörungsrituale." },
    { text = "Alleria und Turalyon sind nicht verheiratet, obwohl sie seit über tausend Jahren zusammen sind." },
}

IMAGO.LoreSnippets["DID_YOU_KNOW"] = {
    { text = "Azeroth kann sich auf fünf verschiedene Dinge beziehen: Azeroth den Titanen, Azeroth den Planeten, Azeroth den Kontinent (Östliche Königreiche), Azeroth die Region (südlich von Khaz Modan) und Azeroth das Königreich (heute Königreich Sturmwind)." },
    { text = "Goblins sind ein fehlgeschlagenes Experiment des Titanenhüters Mimiron." },
    { text = "Der Dämmerwald war einst als Hellerwald bekannt, bis zum Tod des Wächters Medivh. Sein Tod löste eine Welle von Teufelsenergie aus, die eine ewige Nacht verursachte." },
    { text = "Elfen sind magisch weiterentwickelte Trolle." },
    { text = "Die Leere ist nicht leer, sondern eine Verschmelzung von Energien, ähnlich dem brennenden Inneren eines Sterns. Viele wurden von ihr in den Wahnsinn getrieben." },
    { text = "Die Getriebenen sind Blutelfen, die ihrer Magiesucht erlegen sind und dadurch verwildert und deformiert wurden." },
    { text = "Oger sind überraschend gute Schiffsbauer und Seeleute." },
    { text = "Tartek der Wütende war eine der mächtigsten Monstrositäten, die je erschaffen wurden. Wir wissen von seiner Existenz nur durch eine einzige Schriftrolle der Geißel in der Schwarzen Festung." },
}

IMAGO.LoreSnippets["HISTORICAL_FACT"] = {
    { text = "Die gefürchtete C'thraxxi-Kreatur namens Kith'ix war vor Jahrtausenden ein General der Alten Götter. Er wurde besiegt und in Zul'Aman begraben, wo sein Körper bis heute ruht." },
    { text = "Dath'remar Sonnenwanderer gründete Quel'Thalas nach dem Krieg der Ahnen. Seine Statue befindet sich auf der Insel der Sonnenwanderer." },
    { text = "Der Strahlende Gesang wurde nicht nur auf Azeroth gehört, sondern auch auf der weit entfernten Welt K'aresh, kurz bevor diese zerstört wurde." },
    { text = "Die Todesschneise wurde durch den Sonnenbrunnen fast vollständig geheilt. Heutzutage sind in Silbermond nur noch wenige Spuren von Arthas' Invasion sichtbar." },
    { text = "Die Defiasbruderschaft wurde ursprünglich gegründet, nachdem das Königreich Sturmwind sich weigerte, die Steinmetze für ihre Arbeit am Wiederaufbau von Sturmwind zu bezahlen." },
    { text = "Der Sonnenbrunnen ist etwa 7.000 Jahre alt." },
    { text = "Die Stadt Sturmwind wurde etwa 1.200 Jahre vor dem Ersten Krieg gegründet. Zur Zeit von Midnight ist die Stadt physisch uralt, aber ein Großteil ihrer sichtbaren Infrastruktur wurde in den letzten 30–40 Jahren der In-Universe-Geschichte neu aufgebaut." },
    { text = "Halduron Wolkenglanz ist der erste Waldläufergeneral von Silbermond seit mindestens drei Generationen, der kein Windläufer ist." },
    { text = "Der Orc Broxigar benutzte eine verzauberte Holzaxt, um in das Bein von Sargeras zu schneiden. Er ist einer der wenigen Sterblichen, von denen bekannt ist, dass sie den Titanen verletzt haben." },
    { text = "Tanaris war einst ein üppiger Dschungel, bis die Große Teilung die Welt zerschmetterte und das Klima dauerhaft veränderte." },
    { text = "Die ersten Paladine wurden im Zweiten Krieg erschaffen, um der Schwarzen Magie der Horde entgegenzuwirken. Es war ein Sammelsurium aus Priestern mit Militärausbildung und Rittern, die heilige Schriften studieren mussten – doch die verzweifelte Maßnahme zeigte Wirkung." },
    { text = "75 Jahre vor dem Ersten Krieg wurde das Königreich Sturmwind beinahe von Gnolle vernichtet." },
    { text = "Die dornigen Ranken, aus denen der Kral der Klingenhauer und die Hügel von Razorfen bestehen, sind die sterblichen Überreste von Agamaggan, der Schweinegott. Er fiel im Kampf gegen die Brennende Legion während des Krieges der Ahnen." },
    { text = "Gnome fehlten im Dritten Krieg, weil Gnomregan zu diesem Zeitpunkt von Troggs belagert wurde." },
    { text = "Menschen entdeckten die heiligen Kräfte des Lichts vor etwa 3.000 Jahren während der Trollkriege. Mereldar war die erste menschliche Priesterin, die seine heilende Kraft herbeirief." },
    { text = "Vor etwa 250 Jahren versuchte der Schwarzeisen-Zauberthan Thaurissan, Ragnaros den Feuerfürsten zu beschwören, um seine Feinde zu vernichten. Die daraus folgende Verwüstung tötete ihn und erschuf den Schwarzfels." },
    { text = "Zweiköpfige Oger entstanden im Zweiten Krieg, als Gul'dan alte elfische Runensteine in Bauwerke umwandelte, die als Sturmaltar bekannt sind." },
    { text = "Im Zweiten Krieg verlor König Perenolde von Alterac den Glauben und wechselte die Seiten, um sich mit der Horde zu verbünden. Die Allianz zerstörte Alterac als Vergeltung für diesen Verrat." },
    { text = "Das Mondfest feiert das Ende des Krieges der Ahnen, bei dem die Völker Azeroths die Invasion der Brennenden Legion vor zehntausend Jahren zurückschlugen." },
    { text = "Im Zweiten Krieg nahm der Ork Nekros Schädelbrecher Alexstrasza gefangen und zwang ihre Kinder, für die Horde zu kämpfen." },
    { text = "Das antike Draenor war von einem Schwarmbewusstsein aus Pflanzen und Pilzen bedeckt, dem sogenannten Ewigem Wachstum. Es wurde vernichtet, als uralte Arakkoa eine Superwaffe aktivierten, die Sonnenenergie mit verheerender Wirkung einsetzte." },
    { text = "Vor etwa 2.600 Jahren wurde der erste Wächter von Trisfal erschaffen. Diese Magier wurden mit immenser Macht und der Verantwortung ausgestattet, Azeroth vor der Dämoneninvasion zu schützen." },
    { text = "Nach dem Ersten Krieg wurde das Ereignis als so bedeutsam eingestuft, dass der Kalender neu gezählt wurde. Jahr 0 markiert den Zeitpunkt, an dem die Horde zum ersten Mal in Azeroth einmarschierte." },
    { text = "Es gibt eine \"einzig wahre Zeitlinie\", und der Bronzene Drachenschwarm widmet sich ihrer Bewahrung." },
}
